#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use PDF::API2::Resource::Font::CoreFont;
use PDF::API2::Basic::Date;

sub extraire_infos_pdf {
    my $pdf = PDF::API2->open(shift);
    my $n_pages = $pdf->count_pages;

    for my $page (1 .. $n_pages) {
        my $page_obj = $pdf->open_page($page);
        print "Page $page : \n";
        print "  Auteur : " . $page_obj->info->get("/Author") . "\n";
        print "  Date : " . $page_obj->info->get("/CreationDate") . "\n";
        print "  Titre : " . $page_obj->info->get("/Title") . "\n";
        print "  Contenu : \n";
        $page_obj->content->each_subobj(sub {
            my $obj = shift;
            if ($obj->isa("PDF::API2::Content::Text")) {
                print "    " . $obj->text . "\n";
            }
        });
    }
}

extraire_infos_pdf("mon_fichier.pdf");
```

